import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { SharedModule } from 'app/shared/shared.module';



const routes: Routes = [{
  path: 'fdp',
  loadChildren: () => import('./fdp/fdp.module').then(m => m.FDPModule)
},
{
  path: 'mas',
  loadChildren: () => import('./mas/mas.module').then(m => m.MASModule)
}, {
  path: 'opo',
  loadChildren: () => import('./opo/opo.module').then(m => m.OPOModule)
}, {
  path: '',
  redirectTo: 'opo',
  pathMatch: 'full'
}, {
  path: '**',
  redirectTo: 'opo'
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes),
    SharedModule
  ]
})
export class GEModule { }
